<?php include __DIR__.'/_init.php';
if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??''))die('CSRF');
if($_POST['type']==='quiz'){$db->prepare('INSERT INTO quizzes(course_id,title,passing_marks,duration_minutes,retake_limit,status) VALUES(?,?,?,?,?,?)')->execute([(int)$_POST['course_id'],sanitize($_POST['title']),(int)$_POST['passing_marks'],(int)$_POST['duration_minutes'],(int)$_POST['retake_limit'],sanitize($_POST['status'])]);}
if($_POST['type']==='question'){$db->prepare('INSERT INTO quiz_questions(quiz_id,question,marks,sort_order) VALUES(?,?,?,?)')->execute([(int)$_POST['quiz_id'],sanitize($_POST['question']),(int)$_POST['marks'],(int)$_POST['sort_order']]);$qid=$db->lastInsertId();foreach($_POST['options'] as $i=>$op){$db->prepare('INSERT INTO quiz_options(question_id,option_text,is_correct) VALUES(?,?,?)')->execute([$qid,sanitize($op),((int)$_POST['correct_index']===$i)?1:0]);}}
redirect('/admin/quizzes.php');}
$courses=$db->query('SELECT id,title FROM courses')->fetchAll();$quizzes=$db->query('SELECT q.*,c.title course_title FROM quizzes q JOIN courses c ON c.id=q.course_id ORDER BY q.id DESC')->fetchAll();?><h2>Manage Quizzes</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="type" value="quiz"><select name="course_id"><?php foreach($courses as $c):?><option value="<?=$c['id']?>"><?=e($c['title'])?></option><?php endforeach;?></select><input name="title" placeholder="Quiz title"><input name="passing_marks" value="60"><input name="duration_minutes" value="20"><input name="retake_limit" value="2"><select name="status"><option>published</option><option>draft</option></select><button>Create Quiz</button></form><hr><?php foreach($quizzes as $q):?><div><strong><?=e($q['title'])?></strong> (<?=e($q['course_title'])?>)</div><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="type" value="question"><input type="hidden" name="quiz_id" value="<?=$q['id']?>"><input name="question" placeholder="Question"><input name="marks" value="1"><input name="sort_order" value="1"><input name="options[]" placeholder="Option 1"><input name="options[]" placeholder="Option 2"><input name="options[]" placeholder="Option 3"><input name="options[]" placeholder="Option 4"><input name="correct_index" value="0" placeholder="Correct index 0-3"><button>Add Question</button></form><?php endforeach;?>
